INSERT INTO `v1_390f536631661939de9702e77e2368340219a7eaa34bc68c26c2247bdca8f70c` VALUES (191301, "2030/12/31 15:00:00", 191301, 0, 0, 450, 0, 0, 6, 0, 191301, 6, 1, 850, 0, 0, 191301, "かずまさ", 2.22, 1, "【物理】皆から愛される漁師町のポンコツ漁師。\nユニオンバーストは強力なスタン効果を持つが、\n自身のＨＰが50%以下では尻もちをついてしまう。\n\n・通常攻撃とユニオンバーストを駆使して戦う。", "カズマサ", 0, 1, "2015/04/01 15:00:00");
INSERT INTO `v1_390f536631661939de9702e77e2368340219a7eaa34bc68c26c2247bdca8f70c` VALUES (0, "2030/12/31 15:00:00", 191401, 0, 0, 0, 0, 0, 6, 0, 0, 6, 0, 0, 0, 0, 191401, "こっころ", 0.0, 0, "", "コッコロ", 0, 0, "2015/04/01 15:00:00");
INSERT INTO `v1_390f536631661939de9702e77e2368340219a7eaa34bc68c26c2247bdca8f70c` VALUES (100101, "2030/12/31 15:00:00", 191501, 0, 0, 150, 0, 0, 0, 0, 100101, 0, 0, 1600, 0, 0, 191501, "しゅじんこう", 0.0, 0, "残されたわずかな時間で宿題を終わらせんとする\nルーセント学院の生徒。楽しい夏休みの思い出を\n守るため、山積みの宿題へと立ち向かう。", "主人公", 0, 0, "2015/04/01 15:00:00");
